import { BrowserRouter, Routes, Route, Link, useNavigate } from "react-router-dom";
import { Container, Navbar, Nav, Button } from "react-bootstrap"; // Import từ React-Bootstrap
import { useState, useEffect } from "react";
import HomePage from "./pages/HomePage"; 
import LoginPage from "./pages/LoginPage";
import RegisterPage from "./pages/RegisterPage";
import AppNavbar from "./components/AppNavbar"; // Đảm bảo gọi AppNavbar từ đây
import LandingPage from "./pages/LandingPage"; // Thêm trang giới thiệu

function App() {
  const [user, setUser] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    const storedUser = localStorage.getItem("user");
    if (storedUser) {
      setUser(JSON.parse(storedUser)); // Nếu có user thì gán vào state
    }
  }, []);

  return (
    <BrowserRouter>
      <div style={{ fontFamily: "Arial" }}>
        <AppNavbar />  {/* Navbar hiển thị ở đây */}

        <Container>
          <Routes>
            {/* Route cho trang chủ giới thiệu */}
            <Route path="/" element={user ? <HomePage /> : <LandingPage />} />

            {/* Các route khác */}
            <Route path="/home" element={user ? <HomePage user={user} /> : <LoginPage />} />
            <Route path="/login" element={<LoginPage />} />
            <Route path="/register" element={<RegisterPage />} />
            <Route path="*" element={<LoginPage />} />
          </Routes>
        </Container>
      </div>
    </BrowserRouter>
  );
}

export default App;
